INSERT INTO opportunities (type, title, company, company_logo_url, description, location, work_mode, salary, duration, skills_required, application_url, deadline, tags, is_featured, is_active, source) VALUES
('internship', 'Software Engineering Intern', 'Google', 'https://logo.clearbit.com/google.com', 'Join Google as a Software Engineering Intern and work on products used by billions. You will have the opportunity to work on challenging projects and learn from world-class engineers.', 'Mountain View, CA', 'onsite', '$8,500/month', '12 weeks', ARRAY['Python', 'Java', 'C++', 'Algorithms'], 'https://careers.google.com/jobs/google-intern', '2024-02-28', ARRAY['Big Tech', 'Summer 2024', 'Full-time'], true, true, 'LinkedIn'),
('internship', 'Frontend Developer Intern', 'Meta', 'https://logo.clearbit.com/meta.com', 'Build products that connect billions of people. As a Frontend Developer Intern, you will work on React components and improve user experiences across Meta platforms.', 'Menlo Park, CA', 'hybrid', '$9,000/month', '12 weeks', ARRAY['React', 'JavaScript', 'TypeScript', 'CSS'], 'https://metacareers.com/jobs/meta-intern', '2024-03-01', ARRAY['Big Tech', 'React', 'UI/UX'], true, true, 'LinkedIn'),
('internship', 'Backend Engineering Intern', 'Stripe', 'https://logo.clearbit.com/stripe.com', 'Help build the economic infrastructure for the internet. Work on payment processing APIs and distributed systems at one of the most valuable fintech companies.', 'Remote', 'remote', '$7,500/month', '10 weeks', ARRAY['Ruby', 'Go', 'PostgreSQL', 'Distributed Systems'], 'https://stripe.com/jobs/intern', '2024-02-20', ARRAY['Fintech', 'Backend', 'API'], true, true, 'Indeed'),
('internship', 'Data Science Intern', 'Netflix', 'https://logo.clearbit.com/netflix.com', 'Analyze viewer behavior and improve recommendation algorithms. Work with petabytes of data to enhance the Netflix experience for millions.', 'Los Gatos, CA', 'hybrid', '$8,000/month', '12 weeks', ARRAY['Python', 'SQL', 'Machine Learning', 'Tableau'], 'https://jobs.netflix.com/intern', '2024-02-25', ARRAY['ML', 'Analytics', 'Big Data'], false, true, 'Netflix Careers'),
('internship', 'Cloud Engineering Intern', 'Amazon AWS', 'https://logo.clearbit.com/aws.amazon.com', 'Work on the world leading cloud platform. Build and improve services that millions of businesses rely on daily.', 'Seattle, WA', 'onsite', '$7,800/month', '12 weeks', ARRAY['AWS', 'Python', 'Linux', 'DevOps'], 'https://amazon.jobs/intern', '2024-03-05', ARRAY['Cloud', 'DevOps', 'AWS'], true, true, 'LinkedIn'),
('internship', 'Mobile Developer Intern', 'Spotify', 'https://logo.clearbit.com/spotify.com', 'Build the next generation of music streaming apps. Work on iOS or Android development for hundreds of millions of users.', 'New York, NY', 'hybrid', '$7,000/month', '10 weeks', ARRAY['Swift', 'Kotlin', 'iOS', 'Android'], 'https://lifeatspotify.com/intern', '2024-02-22', ARRAY['Mobile', 'Music', 'Streaming'], false, true, 'Spotify Careers'),
('internship', 'Full Stack Developer Intern', 'Airbnb', 'https://logo.clearbit.com/airbnb.com', 'Help create the future of travel. Work on both frontend and backend systems that power the sharing economy.', 'San Francisco, CA', 'hybrid', '$7,200/month', '12 weeks', ARRAY['React', 'Ruby on Rails', 'PostgreSQL', 'GraphQL'], 'https://careers.airbnb.com/intern', '2024-02-28', ARRAY['Full Stack', 'Travel', 'Marketplace'], false, true, 'Indeed'),
('internship', 'Security Engineering Intern', 'Cloudflare', 'https://logo.clearbit.com/cloudflare.com', 'Protect millions of websites from cyber threats. Work on cutting edge security solutions and distributed systems.', 'Austin, TX', 'Remote', '$6,800/month', '10 weeks', ARRAY['Security', 'Networking', 'Go', 'Rust'], 'https://cloudflare.com/careers/intern', '2024-03-01', ARRAY['Security', 'Networking', 'Infrastructure'], false, true, 'Cloudflare Careers'),
('internship', 'Machine Learning Intern', 'OpenAI', 'https://logo.clearbit.com/openai.com', 'Work on groundbreaking AI research. Contribute to projects that push the boundaries of artificial intelligence.', 'San Francisco, CA', 'onsite', '$10,000/month', '12 weeks', ARRAY['Python', 'PyTorch', 'Transformers', 'Deep Learning'], 'https://openai.com/careers/intern', '2024-02-15', ARRAY['AI/ML', 'Research', 'Deep Learning'], true, true, 'OpenAI Careers'),
('internship', 'DevOps Engineering Intern', 'GitLab', 'https://logo.clearbit.com/gitlab.com', 'Build and improve the CI/CD platform used by millions of developers. Work fully remote with a distributed team.', 'Remote', 'remote', '$6,500/month', '10 weeks', ARRAY['Kubernetes', 'Docker', 'Terraform', 'CI/CD'], 'https://about.gitlab.com/jobs/intern', '2024-03-10', ARRAY['DevOps', 'Remote', 'CI/CD'], false, true, 'GitLab Careers');
